class Solution:
    def minimumSumSubarray(self, nums, l, r):
        n = len(nums)
        best = None
        for i in range(n):
            for length in range(l, r + 1):
                j = i + length - 1
                if j >= n:
                    continue
                s = sum(nums[i:j + 1])
                if s > 0 and (best is None or s < best):
                    best = s
        return best if best is not None else -1

