class Solution:
    def minimumSumSubarray(self, nums, l, r):
        n = len(nums)
        best = None
        for i in range(n):
            s = 0
            for j in range(i, n):
                s += nums[j]
                length = j - i + 1
                if length > r:
                    break
                if length >= l and s > 0:
                    if best is None or s < best:
                        best = s
        return best if best is not None else -1

