var minimumSumSubarray = function(nums, l, r) {
    const n = nums.length;
    let best = null;
    for (let i = 0; i < n; i++) {
        let s = 0;
        for (let j = i; j < n; j++) {
            s += nums[j];
            const length = j - i + 1;
            if (length > r) break;
            if (length >= l && s > 0) {
                if (best === null || s < best) best = s;
            }
        }
    }
    return best === null ? -1 : best;
};
